const input = $input.first().json;
const tenant = input.tenant;

if (!tenant || !tenant.admin_whatsapp) throw new Error('Missing tenant.admin_whatsapp');

const reason = input.reason || 'customer_request';
const customerMsg = input.customer_message || '';
const contextSummary = input.context_summary || '';

const reasonLabels = {
  customer_request: 'طلب العميل التحدث مع موظف',
  complaint: 'شكوى من العميل',
  out_of_scope: 'استفسار خارج نطاق البوت',
  negative_sentiment: 'حالة عاطفية سلبية',
  technical_issue: 'مشكلة تقنية',
  vip_priority: 'عميل VIP'
};

const reasonText = reasonLabels[reason] || reason;
const escalationId = `ESC_${new Date().toISOString().slice(0,10).replace(/-/g,'')}_${Math.floor(Math.random() * 9000) + 1000}`;

const adminAlert = `🚨 *تنبيه تصعيد — ${tenant.business_name}*

🆔 رقم التصعيد: ${escalationId}
👤 العميل: ${input.customer?.name || 'غير محدد'}
📞 الرقم: ${input.customer?.phone || 'غير محدد'}

💬 آخر رسالة:
${customerMsg.slice(0, 200)}

📌 السبب: ${reasonText}

${contextSummary ? '📋 سياق:\n' + contextSummary : ''}

🕐 ${new Date().toISOString().slice(0,19).replace('T', ' ')}

⚠️ تواصل مع العميل في أسرع وقت.`;

const customerReply = `لحظة من فضلك يا فندم 🙏\nهحوّلك دلوقتي لزميل من فريق *${tenant.business_name}* يساعدك بشكل أفضل.\nهيتواصل معاك في أقرب وقت ✨`;

return {
  json: {
    tenant: tenant,
    escalation_id: escalationId,
    customer: input.customer || {},
    reason: reason,
    reason_text: reasonText,
    customer_message: customerMsg,
    context_summary: contextSummary,
    admin_alert: adminAlert,
    customer_reply: customerReply,
    timestamp: new Date().toISOString()
  }
};

const input = $input.first().json;
return {
  json: {
    success: true,
    escalation_id: input.escalation_id,
    message: input.customer_reply
  }
};
